{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "$id": "https://claude-code-mastery/meta/unit-frontmatter.schema.json",
  "title": "Unit front matter",
  "description": "Lintable schema for the YAML front matter of every course unit (course/units/NN-slug/unit.md). Source of truth: design.md §6. Enforced by tools/check-frontmatter (R6.AC3, R13.AC4).",
  "type": "object",
  "additionalProperties": false,
  "required": [
    "id",
    "title",
    "stage",
    "depth_tier",
    "use_case",
    "can_do",
    "workflows",
    "coverage_areas",
    "prerequisites",
    "reading_time_min",
    "lab_time_min"
  ],
  "properties": {
    "id": {
      "type": "string",
      "pattern": "^U[0-9]+$",
      "description": "Unique unit ID, matches the use-case catalog (e.g. U5)."
    },
    "title": {
      "type": "string",
      "minLength": 1
    },
    "stage": {
      "type": "string",
      "enum": ["first-wins", "daily-driver", "force-multiplier", "autonomy-scale"],
      "description": "Exactly one stage (R1.AC4)."
    },
    "depth_tier": {
      "type": "string",
      "enum": ["core", "awareness"],
      "description": "Drives which template applies (R4.AC4 / R6.AC1/AC2)."
    },
    "use_case": {
      "type": "string",
      "minLength": 1,
      "description": "The job-to-be-done from the use-case catalog (R2.AC3)."
    },
    "can_do": {
      "type": "array",
      "minItems": 1,
      "uniqueItems": true,
      "items": {
        "type": "string",
        "pattern": "^(C[0-9]+|CV)$"
      },
      "description": "Capability-map IDs this unit advances (R1.AC4); CV permitted."
    },
    "workflows": {
      "type": "array",
      "uniqueItems": true,
      "items": {
        "type": "string",
        "pattern": "^W[0-9]+$"
      },
      "description": "Workflow IDs exercised (R3); [] for non-workflow units."
    },
    "coverage_areas": {
      "type": "array",
      "minItems": 1,
      "uniqueItems": true,
      "items": {
        "type": "integer",
        "minimum": 1
      },
      "description": "Coverage-matrix area #s this unit touches (R4)."
    },
    "prerequisites": {
      "type": "array",
      "uniqueItems": true,
      "items": {
        "type": "string",
        "pattern": "^U[0-9]+$"
      },
      "description": "Prerequisite unit IDs — the authoritative ordering constraint (R6.AC5 / R9.AC2)."
    },
    "reading_time_min": {
      "type": "integer",
      "minimum": 1,
      "description": "Estimated reading time in minutes (R5.AC6)."
    },
    "lab_time_min": {
      "type": "integer",
      "minimum": 0,
      "description": "Estimated lab time in minutes (R5.AC6); 0 only allowed for awareness-tier units with no lab."
    }
  }
}

#!/usr/bin/env python3
"""check-frontmatter (R13.AC4a): every authored unit's YAML front matter validates against
meta/unit-frontmatter.schema.json, and a few cross-file invariants hold (id is unique and known
to the catalog; declared can_do / coverage_areas / workflows reference real entries).

Vacuously green until P5 authors units — exactly what we want from a guard built before content.
"""
import json
import os
import sys

sys.path.insert(0, os.path.dirname(os.path.abspath(__file__)))
from _common import META, Reporter, load_yaml, parse_frontmatter, unit_files  # noqa: E402

import jsonschema  # noqa: E402


def main(argv):
    rep = Reporter("check-frontmatter")
    schema = json.loads((META / "unit-frontmatter.schema.json").read_text(encoding="utf-8"))
    validator = jsonschema.Draft202012Validator(schema)

    catalog = load_yaml(META / "use-case-catalog.yaml")
    cap = load_yaml(META / "capability-map.yaml")
    cov = load_yaml(META / "coverage-matrix.yaml")
    known_units = {u["unit"] for u in catalog["use_cases"]}
    known_caps = {c["id"] for c in cap["capabilities"]}
    known_areas = {a["id"] for a in cov["areas"]}
    valid_workflows = {f"W{i}" for i in range(1, 10)}

    files = unit_files()
    seen_ids = {}
    for path in files:
        rel = path.relative_to(META.parent)
        fm = parse_frontmatter(path)
        if fm is None:
            rep.fail(f"{rel}: no YAML front matter found")
            continue
        errors = sorted(validator.iter_errors(fm), key=lambda e: e.path)
        if errors:
            for e in errors:
                loc = "/".join(str(p) for p in e.path) or "(root)"
                rep.fail(f"{rel}: {loc}: {e.message}")
            continue
        uid = fm["id"]
        if uid in seen_ids:
            rep.fail(f"{rel}: duplicate unit id {uid} (also in {seen_ids[uid]})")
        seen_ids[uid] = rel
        if uid not in known_units:
            rep.fail(f"{rel}: id {uid} is not in the use-case catalog")
        bad_caps = set(fm["can_do"]) - known_caps
        bad_areas = set(fm["coverage_areas"]) - known_areas
        bad_wf = set(fm["workflows"]) - valid_workflows
        bad_prereq = set(fm["prerequisites"]) - known_units
        if bad_caps:
            rep.fail(f"{rel}: unknown can_do ids {sorted(bad_caps)}")
        if bad_areas:
            rep.fail(f"{rel}: unknown coverage_areas {sorted(bad_areas)}")
        if bad_wf:
            rep.fail(f"{rel}: unknown workflow ids {sorted(bad_wf)}")
        if bad_prereq:
            rep.fail(f"{rel}: unknown prerequisite unit ids {sorted(bad_prereq)}")
        if not rep.failures:
            rep.ok(f"{rel}: front matter valid ({uid})")

    if not files:
        rep.ok("no units authored yet — nothing to validate (guard is in place)")
    return rep.done()


if __name__ == "__main__":
    raise SystemExit(main(sys.argv[1:]))

#!/usr/bin/env python3
"""check-traceability (R13.AC5): the two-way traceability the spec promises.

  A. Every requirement R1–R15 is referenced by >= 1 course artifact (meta/, course/, tools/,
     .claude/, .github/ — i.e. the built course, not the spec that defines the requirements).
  B. Every can-do (C1–C17 + CV) traces to >= 1 LAB and >= 1 capstone-rubric dimension.

Parts B (and any not-yet-referenced requirement) depend on content authored in P5/P6. This check
is built before that content (so it guards as soon as content lands), therefore:
  - default mode: unmet items are reported as PENDING and do NOT fail the build;
  - `--strict` (the release / final Definition-of-Done gate): PENDING becomes FAIL.

A lab is detected as a `## Lab` heading in a unit; the can-dos it exercises are the unit's
front-matter `can_do`. Rubric dimensions are lines in course/capstone/rubric.md tagged with the
can-do id they assess, e.g. `- [C6] ...` (convention consumed here; authored in P6).
"""
import os
import re
import sys

sys.path.insert(0, os.path.dirname(os.path.abspath(__file__)))
from _common import (  # noqa: E402
    COURSE, META, ROOT, Reporter, iter_text_files, load_yaml, parse_frontmatter, unit_files,
)

REQ_RE = re.compile(r"\bR(?:1[0-5]|[1-9])\b")
CANDO_TAG_RE = re.compile(r"\b(C(?:1[0-7]|[1-9])|CV)\b")


def main(argv):
    strict = "--strict" in argv
    rep = Reporter("check-traceability")
    cap = load_yaml(META / "capability-map.yaml")
    cids = {c["id"] for c in cap["capabilities"]}

    # A. requirement references across the built course
    scan_roots = [META, COURSE, ROOT / "tools", ROOT / ".claude", ROOT / ".github",
                  ROOT / "README.md", ROOT / "CLAUDE.md"]
    referenced = set()
    for root in scan_roots:
        files = [root] if root.is_file() else list(iter_text_files(root))
        for path in files:
            try:
                referenced |= set(REQ_RE.findall(path.read_text(encoding="utf-8")))
            except (UnicodeDecodeError, IsADirectoryError):
                continue
    all_reqs = {f"R{i}" for i in range(1, 16)}
    missing_reqs = sorted(all_reqs - referenced, key=lambda r: int(r[1:]))
    if missing_reqs:
        rep.pending(f"requirements not yet referenced by a course artifact: {missing_reqs}")
    else:
        rep.ok("every requirement R1–R15 is referenced by a course artifact")

    # B. can-do -> lab and can-do -> rubric dimension
    lab_cands = set()
    for path in unit_files():
        fm = parse_frontmatter(path)
        if fm and "## Lab" in path.read_text(encoding="utf-8"):
            lab_cands |= set(fm.get("can_do", []))
    rubric = COURSE / "capstone" / "rubric.md"
    rubric_cands = set()
    if rubric.exists():
        rubric_cands = set(CANDO_TAG_RE.findall(rubric.read_text(encoding="utf-8")))

    no_lab = sorted(cids - lab_cands)
    no_rubric = sorted(cids - rubric_cands)
    if no_lab:
        rep.pending(f"can-do(s) not yet practiced by a lab: {no_lab}")
    else:
        rep.ok("every can-do is practiced by >=1 lab")
    if no_rubric:
        rep.pending(f"can-do(s) not yet assessed by a rubric dimension: {no_rubric}")
    else:
        rep.ok("every can-do is assessed by >=1 capstone-rubric dimension")

    return rep.done(strict=strict)


if __name__ == "__main__":
    raise SystemExit(main(sys.argv[1:]))
